import json, sys
# Check the most recent state events to see if lifecycle gaps are still live
events = []
with open('.yoyo/state/events.jsonl', 'r') as f:
    for line in f:
        line = line.strip()
        if not line:
            continue
        try:
            events.append(json.loads(line))
        except:
            pass

# Find recent FailureObserved without matching RunCompleted
from collections import defaultdict
runs = defaultdict(dict)
for e in events[-500:]:
    rid = e.get('run_id', '')
    if not rid:
        continue
    et = e.get('type', '')
    if et in ('FailureObserved', 'RunCompleted', 'RunStarted'):
        runs[rid][et] = runs[rid].get(et, 0) + 1

incomplete = {rid: r for rid, r in runs.items() if 'FailureObserved' in r and 'RunCompleted' not in r}
print(f'Recent (last 500 events) incomplete runs: {len(incomplete)}')
for rid, r in incomplete.items():
    print(f'  {rid}: {dict(r)}')

# Check unmatched non-validation completions
unmatched = {rid: r for rid, r in runs.items() if 'RunCompleted' in r and 'FailureObserved' not in r}
print(f'Runs with RunCompleted but no FailureObserved: {len(unmatched)}')
"

