import json, sys
from collections import defaultdict

events = []
with open('.yoyo/state/events.jsonl', 'r') as f:
    for line in f:
        line = line.strip()
        if not line:
            continue
        try:
            events.append(json.loads(line))
        except:
            pass

print(f'Total events: {len(events)}')

runs = defaultdict(dict)
for e in events:
    rid = e.get('run_id', '')
    if not rid:
        continue
    et = e.get('type', '')
    if et in ('FailureObserved', 'RunCompleted', 'RunStarted'):
        runs[rid][et] = runs[rid].get(et, 0) + 1

# Runs with FailureObserved but no RunCompleted
incomplete = {rid: r for rid, r in runs.items() if 'FailureObserved' in r and 'RunCompleted' not in r}
print(f'All-time incomplete runs (FailureObserved, no RunCompleted): {len(incomplete)}')
for rid, r in sorted(incomplete.items())[-10:]:
    print(f'  {rid}: {dict(r)}')

# Runs with RunCompleted but no FailureObserved (unmatched non-validation)
unmatched = {rid: r for rid, r in runs.items() if 'RunCompleted' in r and 'FailureObserved' not in r}
print(f'All-time unmatched runs (RunCompleted, no FailureObserved): {len(unmatched)}')
for rid, r in sorted(unmatched.items())[-10:]:
    print(f'  {rid}: {dict(r)}')
"

